using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
            // Preserve the old property name so existing 500K documents remain queryable.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the default id format from "EntityType|Key" to just "Key".
            // Preserve the old format so existing documents (e.g. "Product|123") are still found.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<ProductIdGenerator>();
        });
    }
}

// Replicates the EF Core 8 id format: "Product|{key}"
class ProductIdGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override string Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
        => $"Product|{entry.Property("Id").CurrentValue}";
    public override bool GeneratesTemporaryValues => false;
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

